import React, { useState } from "react";
import { motion } from "framer-motion";
import TestimonialCard from "./TestimonialCard";

const testimonials = [
  { text: "I am constantly running and solving problems left & right for over 40 hours a week at work." },
  { text: "I replaced coffee with a healthy alternative that keeps me energized all day long, without any crashes or jitters." },
  { text: "I hate water but found a way to drink more thanks to this." },
  { text: "Great product that keeps me hydrated and focused!" },
  { text: "Super refreshing and helps me get through the day." },
  { text: "Helps me focus all day without feeling drained." },
  { text: "My skin looks hydrated and radiant every day." },
];

const PersonalSection = () => {
  const [index, setIndex] = useState(0);

  const visibleTestimonials = testimonials.slice(index, index + 4);

  const handleNext = () => {
    if (index + 4 < testimonials.length) setIndex(index + 1);
  };

  const handlePrev = () => {
    if (index > 0) setIndex(index - 1);
  };

  return (
    <section style={{ textAlign: "center", padding: "4rem 1rem" }}>
      <h2 style={{ fontSize: "2rem", fontWeight: "bold", color: "black", marginBottom: "2rem" }}>
        LOVED BY THOUSANDS
      </h2>

      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: "1rem" }}>
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handlePrev}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 40,
            height: 40,
            borderRadius: "50%",
            fontSize: "1.5rem",
            border: "none",
            cursor: "pointer",
          }}
        >
          ◀
        </motion.button>

        <div style={{ display: "flex", gap: "1rem", overflow: "hidden" }}>
          {visibleTestimonials.map((testimonial, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -50 }}
              transition={{ duration: 0.3 }}
            >
              <TestimonialCard testimonial={testimonial} />
            </motion.div>
          ))}
        </div>

        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={handleNext}
          style={{
            backgroundColor: "#154734",
            color: "#e4d0a9",
            width: 40,
            height: 40,
            borderRadius: "50%",
            fontSize: "1.5rem",
            border: "none",
            cursor: "pointer",
          }}
        >
          ▶
        </motion.button>
      </div>
    </section>
  );
};

export default PersonalSection;
